'use client'
import { cn } from '@cascivo/core'
import { forwardRef, type HTMLAttributes, type KeyboardEvent } from 'react'
import styles from './button-group.module.css'

export interface ButtonGroupProps extends HTMLAttributes<HTMLDivElement> {
  orientation?: 'horizontal' | 'vertical'
  size?: 'sm' | 'md' | 'lg'
  /** Enable arrow-key roving focus across the group's focusable buttons. */
  roving?: boolean
  loop?: boolean
}

/** Focusable, non-disabled controls inside the group, in DOM order. */
function focusableItems(group: HTMLElement): HTMLElement[] {
  return Array.from(group.querySelectorAll<HTMLElement>('button, a[href], [tabindex]')).filter(
    (el) => !el.hasAttribute('disabled') && el.getAttribute('aria-disabled') !== 'true',
  )
}

export const ButtonGroup = forwardRef<HTMLDivElement, ButtonGroupProps>(function ButtonGroup(
  {
    orientation = 'horizontal',
    size = 'md',
    roving = false,
    loop = false,
    className,
    onKeyDown,
    children,
    ...props
  },
  ref,
) {
  const handleKeyDown = (event: KeyboardEvent<HTMLDivElement>) => {
    onKeyDown?.(event)
    if (!roving) return
    const horizontal = orientation === 'horizontal'
    const forward = horizontal ? 'ArrowRight' : 'ArrowDown'
    const back = horizontal ? 'ArrowLeft' : 'ArrowUp'
    if (![forward, back, 'Home', 'End'].includes(event.key)) return

    const items = focusableItems(event.currentTarget)
    if (items.length === 0) return
    const current = items.indexOf(document.activeElement as HTMLElement)
    if (current === -1) return

    let next = current
    if (event.key === forward) next = current + 1
    else if (event.key === back) next = current - 1
    else if (event.key === 'Home') next = 0
    else if (event.key === 'End') next = items.length - 1

    if (next < 0) next = loop ? items.length - 1 : 0
    if (next >= items.length) next = loop ? 0 : items.length - 1

    event.preventDefault()
    items[next]?.focus()
  }

  return (
    <div
      role="group"
      data-orientation={orientation}
      data-size={size}
      className={cn(styles['buttonGroup'], className as string | undefined)}
      ref={ref}
      onKeyDown={handleKeyDown}
      {...props}
    >
      {children}
    </div>
  )
})

@layer cascivo.component {
  .buttonGroup {
    display: inline-flex;
    --_radius: var(--cascivo-button-radius, var(--cascivo-radius-control));

    &[data-orientation='horizontal'] {
      flex-direction: row;
    }

    &[data-orientation='vertical'] {
      flex-direction: column;
    }

    /* Collapse the seams between joined children. The children keep their own
       border-radius on the outer edges only; inner corners are squared off. */
    & > * {
      border-radius: 0;
    }

    /* Horizontal: round the inline (leading/trailing) corners, collapse seams. */
    &[data-orientation='horizontal'] {
      & > :first-child {
        border-start-start-radius: var(--_radius);
        border-end-start-radius: var(--_radius);
      }

      & > :last-child {
        border-start-end-radius: var(--_radius);
        border-end-end-radius: var(--_radius);
      }

      & > :not(:first-child) {
        margin-inline-start: -1px;
      }
    }

    /* Vertical: round the block (top/bottom) corners, collapse seams. */
    &[data-orientation='vertical'] {
      & > :first-child {
        border-start-start-radius: var(--_radius);
        border-start-end-radius: var(--_radius);
      }

      & > :last-child {
        border-end-start-radius: var(--_radius);
        border-end-end-radius: var(--_radius);
      }

      & > :not(:first-child) {
        margin-block-start: -1px;
      }
    }

    /* Keep the focused/hovered child above its neighbors so its full border shows. */
    & > :hover,
    & > :focus-visible,
    & > :focus-within {
      position: relative;
      z-index: 1;
    }
  }
}
